import React, { useState, useEffect } from 'react';
import { uploadFile, getCoursesForUpload } from '../services/uploadService';
import { useAuth } from '../contexts/AuthContext';
import './Upload.css';

const Upload = () => {
  const { user, isAuthenticated } = useAuth();
  
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [courses, setCourses] = useState([]);
  const [loadingCourses, setLoadingCourses] = useState(true);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    course_id: '',
    type: 'notes'
  });

  const fetchCourses = async () => {
    try {
      setLoadingCourses(true);
      const coursesData = await getCoursesForUpload();
      
      if (coursesData && Array.isArray(coursesData)) {
        setCourses(coursesData);
      } else {
        setCourses([]);
      }
    } catch (error) {
      console.error('Error fetching courses:', error);
      setCourses([]);
    } finally {
      setLoadingCourses(false);
    }
  };

  useEffect(() => {
    fetchCourses();
  }, []);

  if (!isAuthenticated) {
    return (
      <div>
        <div>
          <div>🔒</div>
          <h2>Login Required</h2>
          <p>
            You need to be logged in to share study materials with the community.
            This helps us maintain quality and give credit to contributors.
          </p>
          <div>
            <button onClick={() => window.location.href = '/login'}>
              🔐 Login Now
            </button>
            <button onClick={() => window.location.href = '/register'}>
              📝 Create Account
            </button>
          </div>
        </div>
      </div>
    );
  }
  
  const handleAddSampleCourses = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/add-courses-public', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });
      
      const data = await response.json();
      
      if (response.ok) {
        alert(`✅ ${data.message || 'Courses added successfully!'}`);
        fetchCourses();
      } else {
        alert(`❌ ${data.error || 'Failed to add courses'}`);
      }
    } catch (error) {
      console.error('Error:', error);
      alert('❌ Network error. Check backend connection.');
    }
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      if (selectedFile.size > 10 * 1024 * 1024) {
        alert('❌ File size exceeds 10MB limit');
        e.target.value = '';
        return;
      }
      setFile(selectedFile);
    }
  };

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleUpload = async () => {
    if (!file) {
      alert('❌ Please select a file');
      return;
    }
    if (!formData.title.trim()) {
      alert('❌ Please enter title');
      return;
    }
    if (!formData.course_id) {
      alert('❌ Please select a course');
      return;
    }

    const data = new FormData();
    data.append('file', file);
    data.append('title', formData.title);
    data.append('description', formData.description);
    data.append('course_id', formData.course_id);
    data.append('type', formData.type);

    setUploading(true);

    try {
      const result = await uploadFile(data);
      
      if (result.status === 'pending' || result.message?.includes('approval')) {
        alert(`✅ ${result.message}\n\n📝 Status: Under Review\n👑 Admin approval required\n⏳ Will be visible after approval`);
      } else {
        alert(`✅ ${result.message || 'Upload successful!'}`);
      }
      
      setFile(null);
      setFormData({
        title: '',
        description: '',
        course_id: '',
        type: 'notes'
      });
      document.getElementById('fileInput').value = '';
      
    } catch (error) {
      alert(`❌ Upload failed: ${error.message || 'Check console for details'}`);
      console.error('Upload error:', error);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div>
      <header>
        <h1>Upload Study Materials</h1>
        <p>
          Share your notes, PYQs, and study materials
          <br />
          <small>
            🔒 Login required | 👑 Admin approval needed
          </small>
        </p>
      </header>

      <div>
        <div>
          {user?.name?.charAt(0)?.toUpperCase() || 'U'}
        </div>
        <div>
          <p>
            Uploading as: <span>{user?.name}</span>
          </p>
          <p>
            {user?.branch} • Semester {user?.semester} • {user?.email}
          </p>
        </div>
      </div>

      {courses.length === 0 && !loadingCourses && (
        <div>
          <h3>⚠️ No Courses Found!</h3>
          <p>Add sample courses to continue uploading</p>
          <button onClick={handleAddSampleCourses}>
            ➕ Add Sample Courses
          </button>
          <p>
            This adds 6 sample courses (Data Structures, Digital Electronics, etc.)
          </p>
        </div>
      )}

      <div>
        <input
          type="file"
          id="fileInput"
          onChange={handleFileChange}
          accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.jpg,.jpeg,.png"
        />
        <label htmlFor="fileInput">
          📁 Choose File to Upload
        </label>
        
        {file && (
          <div>
            <p><strong>Selected:</strong> {file.name}</p>
            <p><strong>Size:</strong> {(file.size / 1024).toFixed(2)} KB</p>
            <p><strong>Type:</strong> {file.type}</p>
          </div>
        )}
        
        <p>
          📎 Supported: PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, JPEG, PNG
          <br />
          ⚠️ Maximum file size: 10MB
        </p>
      </div>

      <div>
        <div>
          <label>Title <span>*</span></label>
          <input
            type="text"
            name="title"
            placeholder="Enter descriptive title"
            value={formData.title}
            onChange={handleInputChange}
            disabled={courses.length === 0}
          />
        </div>

        <div>
          <label>Description</label>
          <textarea
            name="description"
            placeholder="Add description about the material (optional)"
            value={formData.description}
            onChange={handleInputChange}
            disabled={courses.length === 0}
          />
        </div>

        <div>
          <label>Course <span>*</span></label>
          {loadingCourses ? (
            <div>
              ⏳ Loading courses...
            </div>
          ) : courses.length === 0 ? (
            <div>
              ⚠️ No courses available
            </div>
          ) : (
            <select
              name="course_id"
              value={formData.course_id}
              onChange={handleInputChange}
              required
            >
              <option value="">Select a course</option>
              {courses.map(course => (
                <option key={course.id} value={course.id}>
                  {course.name} ({course.branch} - Sem {course.semester})
                </option>
              ))}
            </select>
          )}
        </div>

        <div>
          <label>Type <span>*</span></label>
          <select
            name="type"
            value={formData.type}
            onChange={handleInputChange}
            disabled={courses.length === 0}
          >
            <option value="notes">📄 Notes</option>
            <option value="pyq">📝 Previous Year Questions (PYQ)</option>
            <option value="syllabus">📋 Syllabus</option>
          </select>
        </div>

        <button
          onClick={handleUpload}
          disabled={uploading || courses.length === 0 || !file || !formData.title || !formData.course_id}
        >
          {uploading ? '⏳ Uploading...' : '📤 Upload Material'}
        </button>

        <div>
          <p>
            <span>⚠️</span>
            <span>
              <strong>Note:</strong> All uploads require admin approval. 
              Your file will be visible after review.
            </span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Upload;
